<?php
 declare(strict_types=1); namespace tapmeppe\composer\summons; use Symfony\Component\Console\Command\Command; use Symfony\Component\Console\Input\InputArgument; use Symfony\Component\Console\Input\InputInterface; use Symfony\Component\Console\Input\InputOption; use Symfony\Component\Console\Output\OutputInterface; class Administrator extends \tapmeppe\composer\helpers\Summon { protected static $defaultName = 'governance:administrator'; protected function configure(): void { $this ->describe('This command is used to create the first administrator.') ->addArgument('email', InputArgument::REQUIRED, 'The administrator email address.') ->addArgument('password', InputArgument::REQUIRED, 'The administrator password.') ->addArgument('name', InputArgument::REQUIRED, 'The administrator first & last name.') ->addOption('language', 'l', InputOption::VALUE_REQUIRED, 'The administrator language.', 'en') ->addOption('username', 'u', InputOption::VALUE_REQUIRED, 'The administrator username.', 'administrator'); } protected function execute(InputInterface $input, OutputInterface $output): int { try { $admin = $this->app->dataStorage->findOne('system/users', ['active' => true, 'role' => 'admin']); if ($admin) throw new \Exception('At least one active administrator already exists.', Command::FAILURE); $parameters = (object) $this->getParameters($input, ['email', 'password', 'name'], ['language', 'username']); $this->app->dataStorage->save('system/users', [ '_created' => $now = time(), '_modified' => $now, 'active' => true, 'email' => $parameters->email, 'i18n' => $parameters->language, 'name' => $parameters->name, 'password' => $this->app->hash($parameters->password), 'role' => 'admin', 'theme' => 'auto', 'user' => $parameters->username, ]); $this->app->trigger('app.system.install'); $output->writeln("<info>[✓]</info> Administrator '$parameters->email' has been created."); return Command::SUCCESS; } catch (\Throwable $throwable) { $output->writeln("<error>[x] {$throwable->getMessage()}</error>"); return Command::FAILURE; } } } 